def merge_strings(str1, str2):
    from collections import Counter

    # Count characters in both strings
    count1 = Counter(str1)
    count2 = Counter(str2)

    # Create a sorted list of unique characters from both strings
    unique_chars = sorted(set(str1 + str2))

    result = []

    while unique_chars:
        for char in unique_chars:
            if count1[char] > 0 or count2[char] > 0:
                # If we can take from str1 or str2, we take the lexicographically smaller option
                if count1[char] > 0 and (count2[char] == 0 or char <= min(count2.elements())):
                    result.append(char)
                    count1[char] -= 1
                elif count2[char] > 0:
                    result.append(char)
                    count2[char] -= 1
                break
        else:
            break

        # Remove the character if its count is zero
        if count1[char] == 0:
            unique_chars.remove(char)
        if count2[char] == 0:
            unique_chars.remove(char)

    return ''.join(result)

